const checkpoints = [];

const searchContexts = JSON.parse(localStorage.getItem('search_contexts') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');
const rentals = JSON.parse(localStorage.getItem('rental_properties') || '[]');
const destinations = JSON.parse(localStorage.getItem('destinations') || '[]');

// Helper: build destination map
const destMap = new Map();
destinations.forEach(d => destMap.set(d.id, d));

function isOnOahu(rental) {
  let dest = destMap.get(rental.destination_id);
  while (dest) {
    if (dest.id === 'oahu') return true;
    dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
  }
  return false;
}

// All rentals that match the task criteria
const qualifyingRentals = rentals.filter(r => {
  if (!isOnOahu(r)) return false;
  if (r.property_type !== 'condo') return false;
  if (r.bedrooms_count !== 1) return false;
  if (!r.is_oceanfront) return false;
  if ((r.base_nightly_rate || 0) > 250) return false;
  return true;
});

let cheapestRental = null;
if (qualifyingRentals.length > 0) {
  cheapestRental = qualifyingRentals
    .slice()
    .sort((a, b) => (a.base_nightly_rate || 0) - (b.base_nightly_rate || 0))[0];
}

// CP1 (0.30): User ran a search on Oahu with filters consistent with an oceanfront 1BR condo under $250/night
let filterUsed = false;
if (Array.isArray(searchContexts) && searchContexts.length > 0 && qualifyingRentals.length > 0) {
  filterUsed = searchContexts.some(ctx => {
    // Destination must be Oahu or its descendants
    let dest = destMap.get(ctx.destination_id);
    let onOahu = false;
    while (dest) {
      if (dest.id === 'oahu') { onOahu = true; break; }
      dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
    }
    if (!onOahu) return false;
    if (ctx.property_type_filter && ctx.property_type_filter !== 'condo') return false;
    if (ctx.min_bedrooms && ctx.min_bedrooms < 1) return false;
    if (ctx.max_price_per_night && ctx.max_price_per_night > 250) return false;
    const amenities = Array.isArray(ctx.amenities_filter) ? ctx.amenities_filter : [];
    if (!amenities.includes('oceanfront')) return false;
    return true;
  });
}
checkpoints.push({ passed: filterUsed, weight: 0.30 });

// Find bookings that match the stay + property constraints
const qualifyingBookings = bookings.filter(b => {
  const rental = rentals.find(r => r.id === b.rental_property_id);
  if (!rental) return false;
  if (!isOnOahu(rental)) return false;
  if (rental.property_type !== 'condo') return false;
  if (rental.bedrooms_count !== 1) return false;
  if (!rental.is_oceanfront) return false;
  if ((rental.base_nightly_rate || 0) > 250) return false;
  if (b.adults_count !== 2) return false;
  if (b.children_count !== 0) return false;
  if (b.nights !== 4) return false;
  return true;
});

// CP2 (0.30): User started a booking that matches the 4-night, 2-adult, oceanfront 1BR condo under $250/night on Oahu
checkpoints.push({ passed: qualifyingBookings.length > 0, weight: 0.30 });

// CP3 (0.40): Among all qualifying rentals, the booked one is the cheapest option
let bookedCheapest = false;
if (cheapestRental && qualifyingBookings.length > 0) {
  bookedCheapest = qualifyingBookings.some(b => b.rental_property_id === cheapestRental.id);
}
checkpoints.push({ passed: bookedCheapest, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const searchContexts = JSON.parse(localStorage.getItem('search_contexts') || '[]');
const wishlists = JSON.parse(localStorage.getItem('wishlists') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');
const rentals = JSON.parse(localStorage.getItem('rental_properties') || '[]');
const destinations = JSON.parse(localStorage.getItem('destinations') || '[]');

const destMap = new Map();
destinations.forEach(d => destMap.set(d.id, d));

function rentalInIsland(rental, islandId) {
  let dest = destMap.get(rental.destination_id);
  while (dest) {
    if (dest.id === islandId) return true;
    dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
  }
  return false;
}

// All qualifying 2BR entire homes on Maui and Kauai with rating >= 4.5
const qualifyingMaui = rentals.filter(r =>
  rentalInIsland(r, 'maui') &&
  r.property_type === 'entire_home' &&
  (r.bedrooms_count || 0) >= 2 &&
  (r.rating || 0) >= 4.5
);

const qualifyingKauai = rentals.filter(r =>
  rentalInIsland(r, 'kauai') &&
  r.property_type === 'entire_home' &&
  (r.bedrooms_count || 0) >= 2 &&
  (r.rating || 0) >= 4.5
);

const matchingProperties = qualifyingMaui.concat(qualifyingKauai);

let lowestProperty = null;
if (matchingProperties.length > 0) {
  lowestProperty = matchingProperties
    .slice()
    .sort((a, b) => (a.cleaning_fee || 0) - (b.cleaning_fee || 0))[0];
}

// CP1 (0.20): User has at least one search context for Maui or Kauai with filters for entire homes, 2+ bedrooms, rating >= 4.5
let filterUsed = false;
if (Array.isArray(searchContexts) && searchContexts.length > 0) {
  filterUsed = searchContexts.some(ctx => {
    const dest = destMap.get(ctx.destination_id);
    let onMauiOrKauai = false;
    let d = dest;
    while (d) {
      if (d.id === 'maui' || d.id === 'kauai') { onMauiOrKauai = true; break; }
      d = d.parent_destination_id ? destMap.get(d.parent_destination_id) : null;
    }
    if (!onMauiOrKauai) return false;
    if (ctx.property_type_filter && ctx.property_type_filter !== 'entire_home') return false;
    if (ctx.min_bedrooms && ctx.min_bedrooms < 2) return false;
    if (ctx.min_rating && ctx.min_rating < 4.5) return false;
    return true;
  });
}
checkpoints.push({ passed: filterUsed, weight: 0.20 });

// Determine default Favorites wishlist
const defaultWishlist = wishlists.find(w => w && w.is_default) || null;
let qualifyingSaved = [];
if (defaultWishlist && matchingProperties.length > 0) {
  const defaultItems = wishlistItems.filter(wi => wi.wishlist_id === defaultWishlist.id);
  const matchingIds = new Set(matchingProperties.map(r => r.id));
  qualifyingSaved = defaultItems.filter(wi => matchingIds.has(wi.rental_property_id));
}

// CP2 (0.30): User saved at least one qualifying Maui/Kauai 2BR entire home (rating >= 4.5) into the default Favorites wishlist
checkpoints.push({ passed: qualifyingSaved.length > 0, weight: 0.30 });

// CP3 (0.50): The Favorites wishlist contains the qualifying home with the lowest cleaning fee among all matching properties
let savedLowest = false;
if (defaultWishlist && lowestProperty) {
  const defaultItems = wishlistItems.filter(wi => wi.wishlist_id === defaultWishlist.id);
  savedLowest = defaultItems.some(wi => wi.rental_property_id === lowestProperty.id);
}
checkpoints.push({ passed: savedLowest, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

