const paymentStepReached = paymentStepReachedRaw === 'true' || paymentStepReachedRaw === '1';

const destMap = new Map();
destinations.forEach(d => destMap.set(d.id, d));

function contextOnBigIsland(ctx) {
  let dest = destMap.get(ctx.destination_id);
  while (dest) {
    if (dest.id === 'island_of_hawaii') return true;
    dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
  }
  return false;
}

function rentalOnBigIsland(rental) {
  let dest = destMap.get(rental.destination_id);
  while (dest) {
    if (dest.id === 'island_of_hawaii') return true;
    dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
  }
  return false;
}

function calcNights(ci, co) {
  if (!ci || !co) return 0;
  const inD = new Date(ci);
  const outD = new Date(co);
  const msPerDay = 24 * 60 * 60 * 1000;
  const diff = Math.round((outD.getTime() - inD.getTime()) / msPerDay);
  return diff > 0 ? diff : 0;
}

const activeSearch = searchContexts.find(c => c.id === activeSearchId) || null;

// CP1 (0.25): Active search is on Big Island with correct filters (entire home, 3+ bedrooms, pool & Wi-Fi, <= $450, 5 nights, 4 adults + 2 children)
let searchOk = false;
if (activeSearch && contextOnBigIsland(activeSearch)) {
  const nights = calcNights(activeSearch.check_in, activeSearch.check_out);
  const amenities = Array.isArray(activeSearch.amenities_filter) ? activeSearch.amenities_filter : [];
  const hasPool = amenities.includes('pool');
  const hasWifi = amenities.includes('wifi');
  const maxPriceOk = !activeSearch.max_price_per_night || activeSearch.max_price_per_night <= 450;
  const typeOk = !activeSearch.property_type_filter || activeSearch.property_type_filter === 'entire_home';
  const bedroomsOk = !activeSearch.min_bedrooms || activeSearch.min_bedrooms >= 3;
  const guestsOk = activeSearch.adults_count === 4 && activeSearch.children_count === 2;
  searchOk = nights === 5 && hasPool && hasWifi && maxPriceOk && typeOk && bedroomsOk && guestsOk;
}
checkpoints.push({ passed: searchOk, weight: 0.25 });

const activeBooking = bookings.find(b => b.id === activeBookingId) || null;
const activeRental = activeBooking ? rentals.find(r => r.id === activeBooking.rental_property_id) : null;

// Qualifying rentals by property constraints
