  if (!rentalOnBigIsland(r)) return false;
  if (r.property_type !== 'entire_home') return false;
  if ((r.bedrooms_count || 0) < 3) return false;
  if (!r.has_pool || !r.has_wifi) return false;
  if ((r.base_nightly_rate || 0) > 450) return false;
  return true;
});

let cheapestRental = null;
if (qualifyingRentals.length > 0) {
  cheapestRental = qualifyingRentals
    .slice()
    .sort((a, b) => (a.base_nightly_rate || 0) - (b.base_nightly_rate || 0))[0];
}

