if (activeBooking && activeRental && rentalOnBigIsland(activeRental)) {
  const guests = (activeBooking.adults_count || 0) + (activeBooking.children_count || 0);
  bookingConstraintsOk =
    activeRental.property_type === 'entire_home' &&
    (activeRental.bedrooms_count || 0) >= 3 &&
    activeRental.has_pool &&
    activeRental.has_wifi &&
    (activeRental.base_nightly_rate || 0) <= 450 &&
    activeBooking.nights === 5 &&
    guests === 6;
}
checkpoints.push({ passed: bookingConstraintsOk, weight: 0.25 });

// CP3 (0.25): Active booking is for the cheapest qualifying rental
let bookedCheapest = false;
if (activeRental && cheapestRental) {
  bookedCheapest = activeRental.id === cheapestRental.id;
}
checkpoints.push({ passed: bookedCheapest, weight: 0.25 });

// CP4 (0.25): User reached payment step without entering payment details and filled expected guest info
let paymentStepOk = false;
if (activeBooking) {
  const guestInfoOk =
    activeBooking.guest_first_name === 'Test' &&
    activeBooking.guest_last_name === 'Family' &&
    activeBooking.guest_email === 'family@example.com' &&
    activeBooking.guest_phone === '555-123-4567';
  const statusOk = activeBooking.status === 'pending_payment' && activeBooking.is_payment_details_entered === false;
  paymentStepOk = paymentStepReached && statusOk && guestInfoOk;
}
checkpoints.push({ passed: paymentStepOk, weight: 0.25 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

