  searchOk = searchContexts.some(ctx => {
    if (!contextOnOahu(ctx)) return false;
    const nights = calcNights(ctx.check_in, ctx.check_out);
    if (nights !== 2) return false;
    const checkIn = ctx.check_in ? new Date(ctx.check_in) : null;
    const monthIsMay = checkIn ? checkIn.getUTCMonth() === 4 : false;
    const day = checkIn ? checkIn.getUTCDay() : -1; // 5 = Fri, 6 = Sat
    const weekendStart = day === 5 || day === 6;
    if (!monthIsMay || !weekendStart) return false;
    if (ctx.adults_count !== 2) return false;
    if ((ctx.pets_count || 0) < 1) return false;
    if (ctx.max_price_per_night && ctx.max_price_per_night > 200) return false;
    const amenities = Array.isArray(ctx.amenities_filter) ? ctx.amenities_filter : [];
    if (!amenities.includes('pet_friendly')) return false;
    if (!amenities.includes('outdoor_space')) return false;
    return true;
  });
}
checkpoints.push({ passed: searchOk, weight: 0.40 });

// Qualifying rentals
const qualifyingRentals = rentals.filter(r =>
  rentalOnOahu(r) &&
  !!r.is_pet_friendly &&
  !!r.has_outdoor_space &&
  (r.base_nightly_rate || 0) < 200
);
const qualifyingIds = new Set(qualifyingRentals.map(r => r.id));

// CP2 (0.60): A host message was sent for a qualifying rental asking if the yard/outdoor area is fully fenced for pets
let messageOk = false;
if (Array.isArray(hostMessages) && hostMessages.length > 0 && qualifyingIds.size > 0) {
  messageOk = hostMessages.some(m => {
    if (!qualifyingIds.has(m.rental_property_id)) return false;
    const text = (m.message_text || '').toLowerCase();
    const mentionsFenced = text.includes('fully fenced');
    const mentionsPetOrDog = text.includes('pet') || text.includes('dog');
    return mentionsFenced && mentionsPetOrDog;
  });
}
checkpoints.push({ passed: messageOk, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const profileRaw = localStorage.getItem('profile');
let profile = null;
try { profile = profileRaw && profileRaw !== 'null' ? JSON.parse(profileRaw) : null; } catch (e) { profile = null; }
const wishlists = JSON.parse(localStorage.getItem('wishlists') || '[]');
const wishlistItems = JSON.parse(localStorage.getItem('wishlist_items') || '[]');
const rentals = JSON.parse(localStorage.getItem('rental_properties') || '[]');
const destinations = JSON.parse(localStorage.getItem('destinations') || '[]');

const destMap = new Map();
destinations.forEach(d => destMap.set(d.id, d));

function rentalOnIsland(rental, islandId) {
  let dest = destMap.get(rental.destination_id);
  while (dest) {
    if (dest.id === islandId) return true;
    dest = dest.parent_destination_id ? destMap.get(dest.parent_destination_id) : null;
  }
  return false;
}

// CP1 (0.40): Profile exists and preferred_destination text is 'Hawaii'
let profileOk = false;
if (profile && profile.id) {
  const pref = (profile.preferred_destination || '').toLowerCase();
  profileOk = pref === 'hawaii';
}
checkpoints.push({ passed: profileOk, weight: 0.40 });

// Find 'Summer 2026' wishlist
const summerWishlist = wishlists.find(w => w.name && w.name.toLowerCase() === 'summer 2026');

// CP2 (0.30): 'Summer 2026' wishlist exists
const wishlistExists = !!summerWishlist;
checkpoints.push({ passed: wishlistExists, weight: 0.30 });

// CP3 (0.30): 'Summer 2026' wishlist contains at least one qualifying Maui rental and one qualifying Oahu rental with required price and rating
let itemsOk = false;
if (summerWishlist) {
  const items = wishlistItems.filter(wi => wi.wishlist_id === summerWishlist.id);
  const mauiMatches = items.filter(wi => {
    const r = rentals.find(x => x.id === wi.rental_property_id);
    if (!r) return false;
    return rentalOnIsland(r, 'maui') && (r.base_nightly_rate || 0) <= 300 && (r.rating || 0) >= 4.5;
  });
  const oahuMatches = items.filter(wi => {
    const r = rentals.find(x => x.id === wi.rental_property_id);
    if (!r) return false;
    return rentalOnIsland(r, 'oahu') && (r.base_nightly_rate || 0) <= 220 && (r.rating || 0) >= 4.5;
  });
  itemsOk = mauiMatches.length > 0 && oahuMatches.length > 0;
}
checkpoints.push({ passed: itemsOk, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
